import { NextRequest, NextResponse } from 'next/server';
import { PredictionsDbService } from '@/lib/predictions-db';
import { getRegimeLabel, MarketRegime } from '@/lib/regime-detector';
import { deriveMarketRegime } from '@/lib/prediction-analytics';
import { getAuthenticatedAdmin } from '@/lib/admin-api-auth';

export const dynamic = 'force-dynamic';

const REGIMES: MarketRegime[] = [
  'BULL', 'BEAR', 'SIDEWAYS', 'HIGH_VOLATILITY', 'LOW_VOLATILITY', 'TRENDING', 'MEAN_REVERTING',
];

export async function GET(request: NextRequest) {
  const user = await getAuthenticatedAdmin(request);
  if (!user) return NextResponse.json({ error: 'Unauthorized. Admin access required.' }, { status: 403 });

  try {
    const allPredictions = await PredictionsDbService.getAllPredictions();
    const verified = allPredictions.filter(prediction => prediction.status === 'VERIFIED');

    const regimes = REGIMES.map(regime => {
      const records = verified.filter(record => deriveMarketRegime(record) === regime);
      const correct = records.filter(record => record.prediction_result === 'CORRECT').length;
      const incorrect = records.filter(record => record.prediction_result === 'INCORRECT').length;
      const partial = records.filter(record => record.prediction_result === 'PARTIALLY_CORRECT').length;
      const neutral = records.filter(record => record.prediction_result === 'NEUTRAL').length;
      const evaluated = correct + incorrect + partial;
      const errors = records.flatMap(record => typeof record.error_percentage === 'number' ? [record.error_percentage] : []);

      return {
        regime,
        label: getRegimeLabel(regime),
        total_predictions: records.length,
        correct_predictions: correct,
        incorrect_predictions: incorrect,
        partial_predictions: partial,
        neutral_predictions: neutral,
        accuracy_score: evaluated > 0 ? Number((((correct + partial * 0.5) / evaluated) * 100).toFixed(1)) : null,
        avg_error_percentage: errors.length > 0 ? Number((errors.reduce((sum, error) => sum + error, 0) / errors.length).toFixed(2)) : null,
        data_status: evaluated === 0 ? 'NO_VERIFIED_DATA' : evaluated < 20 ? 'UNRELIABLE' : 'RELIABLE',
      };
    });

    const latestClassified = [...allPredictions]
      .filter(record => REGIMES.includes(deriveMarketRegime(record) as MarketRegime))
      .sort((a, b) => new Date(b.prediction_date).getTime() - new Date(a.prediction_date).getTime())[0];
    const currentRegime = latestClassified
      ? {
          regime: deriveMarketRegime(latestClassified),
          label: getRegimeLabel(deriveMarketRegime(latestClassified) as MarketRegime),
          confidence: null,
          asOf: latestClassified.prediction_date,
        }
      : null;

    return NextResponse.json({
      regimes,
      currentRegime,
      unclassifiedVerifiedCount: verified.filter(record => deriveMarketRegime(record) === 'UNKNOWN').length,
    });
  } catch (err: any) {
    console.error('Failed to compute regime stats:', err);
    return NextResponse.json({ error: err.message || 'Failed to compute regime statistics.' }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { PredictionsDbService } from '@/lib/predictions-db';
import { supabase } from '@/lib/supabase';
import {
  analyzeIndicatorPerformance,
  computeAdaptiveWeights,
  saveWeightSnapshot,
  loadCurrentWeights
} from '@/lib/adaptive-weights';
import { getAuthenticatedAdmin } from '@/lib/admin-api-auth';

export const dynamic = 'force-dynamic';

export async function POST(request: NextRequest) {
  const user = await getAuthenticatedAdmin(request);

  if (!user) {
    return NextResponse.json({ error: 'Unauthorized. Admin access required.' }, { status: 403 });
  }

  try {
    const origin = request.nextUrl.origin;

    // 1. Verify expired predictions
    console.log('[LearningJob] Automatically verifying expired predictions...');
    const newlyVerifiedCount = await PredictionsDbService.autoVerifyExpired(origin);

    // 2. Fetch all predictions to analyze historical performance
    const allPredictions = await PredictionsDbService.getAllPredictions();
    const verifiedPredictions = allPredictions.filter(p => p.status === 'VERIFIED');

    if (verifiedPredictions.length === 0) {
      return NextResponse.json({
        message: 'No verified predictions found in the database. Add verified predictions or run backtest seeder first.',
        newlyVerifiedCount,
        weightsUpdated: false
      });
    }

    // 3. Analyze indicator accuracy & reliability scores
    console.log('[LearningJob] Analyzing indicator performance scores...');
    const performances = analyzeIndicatorPerformance(verifiedPredictions);

    // 4. Compute overall system accuracy (win rate)
    const correctCount = verifiedPredictions.filter(p => p.prediction_result === 'CORRECT').length;
    const partialCount = verifiedPredictions.filter(p => p.prediction_result === 'PARTIALLY_CORRECT').length;
    const incorrectCount = verifiedPredictions.filter(p => p.prediction_result === 'INCORRECT').length;
    const evaluatedCount = correctCount + partialCount + incorrectCount;
    const systemAccuracy = evaluatedCount > 0
      ? ((correctCount + partialCount * 0.5) / evaluatedCount) * 100
      : 0;

    // 5. Compute new adaptive weights using update formulas
    const currentWeights = loadCurrentWeights();
    console.log('[LearningJob] Adjusting weights based on performance delta...');
    const newWeights = computeAdaptiveWeights(performances, currentWeights);
    // 6. Save weight snapshot to history
    saveWeightSnapshot(newWeights, systemAccuracy, verifiedPredictions.length, performances);

    // 7. Sync with SQL database if configured
    if (process.env.NEXT_PUBLIC_SUPABASE_URL && !process.env.NEXT_PUBLIC_SUPABASE_URL.includes('your-supabase-url')) {
      try {
        console.log('[LearningJob] Syncing indicator performance to Supabase...');
        for (const perf of performances) {
          const { error } = await supabase
            .from('indicator_performance')
            .upsert({
              indicator_name: perf.indicator_name,
              current_weight: perf.current_weight,
              previous_weight: perf.previous_weight,
              accuracy_score: perf.accuracy_score,
              reliability_score: perf.reliability_score,
              last_updated: new Date().toISOString()
            }, { onConflict: 'indicator_name' });

          if (error) {
            console.error(`[LearningJob] Database sync failed for ${perf.indicator_name}:`, error.message);
          }
        }
      } catch (dbErr: any) {
        console.error('[LearningJob] Database sync error:', dbErr.message);
      }
    }

    return NextResponse.json({
      success: true,
      message: `Successfully completed learning cycle. Verified ${newlyVerifiedCount} pending predictions.`,
      newlyVerifiedCount,
      systemAccuracy: Number(systemAccuracy.toFixed(2)),
      totalVerified: verifiedPredictions.length,
      previousWeights: currentWeights,
      updatedWeights: newWeights,
      indicatorPerformance: performances
    });
  } catch (err: any) {
    console.error('[LearningJob] Learning cycle failed:', err);
    return NextResponse.json({ error: err.message || 'Failed to execute learning cycle.' }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { PredictionsDbService } from '@/lib/predictions-db';
import { StockData } from '@/types/stock';
import { getAuthenticatedAdmin } from '@/lib/admin-api-auth';
import { classifySignalStrength } from '@/lib/prediction-analytics';

export const dynamic = 'force-dynamic';

function getTimeframeDays(timeframe: string): number {
  if (timeframe === '1D') return 1;
  if (timeframe === '7D') return 7;
  if (timeframe === '30D') return 30;
  if (timeframe === '90D') return 90;
  if (timeframe === '365D') return 365;
  return 7; // Default fallback
}

export async function POST(request: NextRequest) {
  const user = await getAuthenticatedAdmin(request);

  if (!user) {
    return NextResponse.json({ error: 'Unauthorized. Admin access required.' }, { status: 403 });
  }

  try {
    const pendingPredictions = await PredictionsDbService.getPendingPredictions();

    if (pendingPredictions.length === 0) {
      return NextResponse.json({ message: 'No pending predictions to verify.', verifiedCount: 0 });
    }

    const now = new Date();
    const verifiedPredictions = [];
    const stockCache: Record<string, StockData> = {};

    for (const pred of pendingPredictions) {
      const predDate = new Date(pred.prediction_date);
      const days = getTimeframeDays(pred.timeframe);
      const targetTime = predDate.getTime() + days * 24 * 60 * 60 * 1000;

      // Check if prediction is expired
      if (now.getTime() < targetTime) {
        continue; // Skip predictions that haven't reached target date yet
      }

      // Fetch stock data for historical outcome
      let stockData = stockCache[pred.ticker];
      if (!stockData) {
        try {
          const baseUrl = request.nextUrl.origin;
          const res = await fetch(`${baseUrl}/api/stock/${pred.ticker}`, { cache: 'no-store' });
          if (res.ok) {
            stockData = await res.json();
            stockCache[pred.ticker] = stockData;
          }
        } catch (err) {
          console.error(`Failed to fetch stock data for ticker ${pred.ticker}:`, err);
        }
      }

      if (!stockData || !stockData.history || stockData.history.length === 0) {
        continue; // Skip if we cannot retrieve stock history
      }

      // Find the historical quote closest to the targetTime
      let closestQuote = null;
      let minDiff = Infinity;

      for (const quote of stockData.history) {
        const quoteTime = new Date(quote.date).getTime();
        const diff = Math.abs(quoteTime - targetTime);
        if (diff < minDiff) {
          minDiff = diff;
          closestQuote = quote;
        }
      }

      // Ensure the quote is within a reasonable window (e.g. 5 days) of target date
      // to handle weekends, holidays, and short data timelines.
      if (closestQuote && minDiff <= 5 * 24 * 60 * 60 * 1000) {
        const actualPrice = closestQuote.close;
        const currentPrice = pred.current_price;
        const predictedPrice = pred.predicted_price;

        // Calculate price movement percentage
        const priceChangePercent = ((actualPrice - currentPrice) / currentPrice) * 100;

        // Determine actual direction (using +/- 0.5% threshold)
        let actualDirection: 'UP' | 'DOWN' | 'NEUTRAL' = 'NEUTRAL';
        if (priceChangePercent >= 0.5) {
          actualDirection = 'UP';
        } else if (priceChangePercent <= -0.5) {
          actualDirection = 'DOWN';
        }

        // Classify prediction result
        let result: 'CORRECT' | 'INCORRECT' | 'PARTIALLY_CORRECT' | 'NEUTRAL' = 'NEUTRAL';
        if (pred.predicted_direction === actualDirection) {
          result = pred.predicted_direction === 'NEUTRAL' ? 'NEUTRAL' : 'CORRECT';
        } else {
          if (pred.predicted_direction === 'NEUTRAL' || actualDirection === 'NEUTRAL') {
            result = 'PARTIALLY_CORRECT';
          } else {
            result = 'INCORRECT'; // Opposite direction
          }
        }

        // Calculate absolute error percentage
        const errorPercentage = Number((Math.abs(actualPrice - predictedPrice) / actualPrice * 100).toFixed(4));

        const updates = {
          actual_price: actualPrice,
          actual_direction: actualDirection,
          prediction_result: result,
          error_percentage: errorPercentage,
          verification_date: new Date().toISOString(),
        };

        // Update database record
        await PredictionsDbService.updateVerifiedPrediction(pred.id, updates);

        verifiedPredictions.push({
          id: pred.id,
          ticker: pred.ticker,
          timeframe: pred.timeframe,
          predicted: pred.predicted_direction,
          actual: actualDirection,
          result: result,
          errorPct: errorPercentage,
          signalStrength: classifySignalStrength(pred.confidence_score),
        });
      }
    }

    return NextResponse.json({
      message: `Successfully verified predictions.`,
      verifiedCount: verifiedPredictions.length,
      verified: verifiedPredictions,
    });
  } catch (err: any) {
    console.error('Verify route execution failed:', err);
    return NextResponse.json({ error: err.message || 'Verification execution failed.' }, { status: 500 });
  }
}

// ─── POST /api/backtest/run ───────────────────────────────────────────────────

import { NextRequest, NextResponse } from 'next/server';
import { createJob } from '../../../../lib/backtesting/data-cache';
import { BacktestConfig } from '../../../../lib/backtesting/types';
import { randomUUID } from 'crypto';

export async function POST(req: NextRequest) {
  try {
    const body = await req.json();
    const jobId = randomUUID();

    const config: BacktestConfig = {
      id: jobId,
      name: body.name ?? `Backtest ${new Date().toLocaleDateString()}`,
      timeframe: body.timeframe ?? '5Y',
      models: body.models ?? ['V1'],
      tickerMode: body.tickerMode ?? 'SINGLE',
      tickers: body.tickers ?? [],
      sector: body.sector,
      predictionHorizon: body.predictionHorizon ?? '7D',
      walkForward: body.walkForward ?? false,
      walkForwardConfig: body.walkForwardConfig,
      monteCarloEnabled: body.monteCarloEnabled ?? false,
      monteCarloConfig: body.monteCarloConfig,
      stressTestEnabled: body.stressTestEnabled ?? false,
      stressScenarios: body.stressScenarios,
      createdAt: new Date().toISOString(),
    };

    if (!config.tickers || config.tickers.length === 0) {
      return NextResponse.json({ error: 'No tickers provided' }, { status: 400 });
    }

    // Persist job to SQLite
    createJob(jobId, config);

    // Launch backtest asynchronously (fire and forget)
    launchBacktestAsync(jobId, config);

    return NextResponse.json({ jobId, status: 'QUEUED', message: 'Backtest job created' });
  } catch (err: any) {
    console.error('[/api/backtest/run]', err);
    return NextResponse.json({ error: err.message }, { status: 500 });
  }
}

async function launchBacktestAsync(jobId: string, config: BacktestConfig) {
  try {
    const { runBacktest } = await import('../../../../lib/backtesting/backtest-engine');
    const { rankModels } = await import('../../../../lib/backtesting/model-comparator');
    const { generateOptimizationRecommendations } = await import('../../../../lib/backtesting/auto-optimizer');
    const { buildReport } = await import('../../../../lib/backtesting/report-generator');
    const { saveResults } = await import('../../../../lib/backtesting/data-cache');
    const { runMonteCarlo, computeDailyReturns } = await import('../../../../lib/backtesting/monte-carlo');
    const { runStressTests } = await import('../../../../lib/backtesting/backtest-engine');
    const { getCached } = await import('../../../../lib/backtesting/data-cache');

    const { tickerResults, allRecords, walkForwardResult } = await runBacktest(jobId, config);

    const modelComparison = rankModels(allRecords);
    const optimizationRecs = generateOptimizationRecommendations(allRecords, tickerResults);

    // Monte Carlo (if enabled)
    let monteCarloResults;
    if (config.monteCarloEnabled && config.monteCarloConfig && config.tickers.length > 0) {
      monteCarloResults = [];
      const { updateJobStatus } = await import('../../../../lib/backtesting/data-cache');
      updateJobStatus(jobId, { phase: 'Running Monte Carlo simulations', progress: 85 });
      for (const ticker of config.tickers.slice(0, 3)) { // Limit to first 3 for performance
        const bars = getCached(ticker, '1970-01-01', new Date().toISOString().split('T')[0]);
        if (bars.length > 30) {
          const returns = computeDailyReturns(bars);
          const result = await runMonteCarlo(ticker, returns, config.monteCarloConfig!);
          monteCarloResults.push(result);
        }
      }
    }

    // Stress Tests (if enabled)
    let stressTestResults;
    if (config.stressTestEnabled && config.stressScenarios && config.stressScenarios.length > 0) {
      const { updateJobStatus } = await import('../../../../lib/backtesting/data-cache');
      updateJobStatus(jobId, { phase: 'Running stress tests', progress: 90 });
      stressTestResults = await runStressTests(jobId, config.tickers.slice(0, 5), config.stressScenarios as string[], config.models[0] ?? 'V1');
    }

    const report = buildReport({
      jobId,
      config,
      tickerResults,
      allRecords,
      modelComparison,
      walkForwardResult,
      monteCarloResults,
      stressTestResults,
      optimizationRecs,
    });

    saveResults(jobId, report);
  } catch (err: any) {
    const { updateJobStatus } = await import('../../../../lib/backtesting/data-cache');
    updateJobStatus(jobId, { status: 'FAILED', error: err.message, completedAt: new Date().toISOString() });
    console.error('[BacktestAsync]', err);
  }
}

// ─── GET /api/backtest/status/[jobId] ─────────────────────────────────────────
// Server-Sent Events (SSE) stream for real-time progress

import { NextRequest } from 'next/server';
import { getJob } from '../../../../../lib/backtesting/data-cache';

export const dynamic = 'force-dynamic';

export async function GET(
  req: NextRequest,
  { params }: { params: Promise<{ jobId: string }> }
) {
  const { jobId } = await params;

  const encoder = new TextEncoder();

  const stream = new ReadableStream({
    async start(controller) {
      const send = (data: object) => {
        const msg = `data: ${JSON.stringify(data)}\n\n`;
        controller.enqueue(encoder.encode(msg));
      };

      // Poll job status every 1.5 seconds
      let attempts = 0;
      const MAX_ATTEMPTS = 400; // ~10 minutes

      const poll = async () => {
        if (attempts++ > MAX_ATTEMPTS) {
          send({ type: 'timeout', message: 'Polling timeout' });
          controller.close();
          return;
        }

        const job = getJob(jobId);
        if (!job) {
          send({ type: 'error', message: `Job ${jobId} not found` });
          controller.close();
          return;
        }

        send({
          type: 'progress',
          jobId: job.id,
          status: job.status,
          progress: job.progress,
          phase: job.phase,
          currentTicker: job.currentTicker,
          totalTickers: job.totalTickers,
          completedTickers: job.completedTickers,
          startedAt: job.startedAt,
          error: job.error,
        });

        if (job.status === 'COMPLETED' || job.status === 'FAILED' || job.status === 'CANCELLED') {
          send({ type: 'done', status: job.status });
          controller.close();
          return;
        }

        // Continue polling
        await new Promise(r => setTimeout(r, 1500));
        await poll();
      };

      try {
        await poll();
      } catch (err) {
        controller.close();
      }
    },
  });

  return new Response(stream, {
    headers: {
      'Content-Type': 'text/event-stream',
      'Cache-Control': 'no-cache, no-transform',
      'Connection': 'keep-alive',
      'X-Accel-Buffering': 'no',
    },
  });
}

