import { NextRequest, NextResponse } from 'next/server';
import { generatePrediction } from '@/lib/prediction-engine';
import { StockData } from '@/types/stock';
import { PredictionsDbService } from '@/lib/predictions-db';
import { supabase } from '@/lib/supabase';
import { getStockDataInternal } from '@/app/api/stock/[ticker]/route';

export const dynamic = 'force-dynamic';

export async function GET(
  request: NextRequest,
  { params }: { params: Promise<{ ticker: string }> }
) {
  const { ticker: rawTicker } = await params;
  const ticker = rawTicker.toUpperCase();

  // Read search parameters for timeframe and modelVersion
  const searchParams = request.nextUrl.searchParams;
  const timeframe = searchParams.get('timeframe') || '7D'; // 1D, 7D, 30D, 90D, 365D
  const modelVersion = searchParams.get('model') || 'V1'; // V1, V2, V3

  try {
    // Call our internal stock details directly (bypasses HTTP fetch)
    const stockData = await getStockDataInternal(ticker);

    // Read custom tuning config if stored in cookie
    const tuningCookie = request.cookies.get('sp_ai_tuning');
    let tuningConfig = undefined;
    if (tuningCookie) {
      try {
        tuningConfig = JSON.parse(decodeURIComponent(tuningCookie.value));
      } catch (e) {
        console.error('Failed to parse tuning config cookie:', e);
      }
    }

    // Generate prediction using target model version and timeframe
    const prediction = generatePrediction(
      ticker,
      stockData.quote.price,
      stockData.quote.volume,
      stockData.history,
      stockData.indicators,
      tuningConfig,
      modelVersion as 'V1' | 'V2' | 'V3',
      timeframe
    );

    // Calculate a point forecast predicted_price
    let priceCoef = 0.04;
    if (timeframe === '1D') priceCoef = 0.015;
    else if (timeframe === '30D') priceCoef = 0.08;
    else if (timeframe === '90D') priceCoef = 0.15;
    else if (timeframe === '365D') priceCoef = 0.35;

    let predictedPrice = stockData.quote.price;
    if (prediction.direction === 'UP') {
      predictedPrice = stockData.quote.price * (1 + (prediction.confidence / 100) * priceCoef);
    } else if (prediction.direction === 'DOWN') {
      predictedPrice = stockData.quote.price * (1 - (prediction.confidence / 100) * priceCoef);
    }
    predictedPrice = Number(predictedPrice.toFixed(2));

    // Search historical predictions for similar setup directional accuracy
    const similarSetup = await PredictionsDbService.getSimilarSetupsAccuracy(
      timeframe,
      prediction.confidence,
      ticker
    );

    // Resolve user ID if authenticated
    let userId = null;
    try {
      const authHeader = request.headers.get('Authorization');
      const token = authHeader?.replace('Bearer ', '');
      if (token) {
        const { data: { user } } = await supabase.auth.getUser(token);
        if (user) userId = user.id;
      } else {
        const mockUserCookie = request.cookies.get('sp_mock_user');
        if (mockUserCookie) userId = 'mock-user-id';
      }
    } catch (err) {
      console.warn('Failed to parse user for prediction logging:', err);
    }

    // Save prediction record with nested explainability & metrics
    await PredictionsDbService.logPrediction({
      user_id: userId,
      ticker,
      prediction_date: new Date().toISOString(),
      timeframe,
      current_price: stockData.quote.price,
      predicted_price: predictedPrice,
      predicted_direction: prediction.direction,
      confidence_score: prediction.confidence,
      signal_strength: prediction.signalStrength,
      confidence_before_filter: prediction.confidenceBeforeFilter,
      confidence_after_filter: prediction.confidenceAfterFilter ?? prediction.confidence,
      signal_quality: prediction.signalQuality,
      filter_reason: prediction.filterReason,
      is_tradeable_signal: prediction.isTradeableSignal,
      reliability_grade: prediction.reliabilityGrade,
      stock_reliability_score: prediction.stockReliabilityScore,
      timeframe_reliability_score: prediction.timeframeReliabilityScore,
      reliability_warnings: prediction.reliabilityWarnings,
      regime: prediction.regime,
      volatility_level: prediction.riskTier,
      indicator_setup: prediction.explainability
        ? `${prediction.explainability.trendContribution >= prediction.explainability.volumeContribution ? 'trend' : 'volume'}+${prediction.explainability.macdContribution >= prediction.explainability.rsiContribution ? 'macd' : 'rsi'}`
        : undefined,
      model_version: modelVersion as 'V1' | 'V2' | 'V3',
      metrics: prediction.probabilities ? {
        bullish_probability: prediction.probabilities.bullish,
        bearish_probability: prediction.probabilities.bearish,
        neutral_probability: prediction.probabilities.neutral,
        bear_case_return: prediction.expectedReturns?.bear || 0,
        base_case_return: prediction.expectedReturns?.base || 0,
        bull_case_return: prediction.expectedReturns?.bull || 0,
        risk_score: prediction.riskScore || 5,
        volatility_score: prediction.volatilityScore || 5,
      } : undefined,
      explanation: prediction.explainability ? {
        rsi_contribution: prediction.explainability.rsiContribution,
        macd_contribution: prediction.explainability.macdContribution,
        trend_contribution: prediction.explainability.trendContribution,
        volume_contribution: prediction.explainability.volumeContribution,
        volatility_contribution: prediction.explainability.volatilityContribution,
        sentiment_contribution: prediction.explainability.sentimentContribution,
        support_resistance_contribution: prediction.explainability.supportResistanceContribution,
        ai_reasoning_summary: prediction.explainability.aiReasoningSummary,
      } : undefined,
      similar_accuracy: similarSetup.successRate,
      similar_verified_count: similarSetup.verifiedCount,
    });

    // Attach target price and similar setups to response for frontend
    const responsePayload = {
      ...prediction,
      predictedPrice,
      timeframe,
      similarSetup,
      reliabilityWarnings: prediction.reliabilityWarnings || [],
    };

    return NextResponse.json(responsePayload);
  } catch (err: any) {
    console.error(`Prediction calculation/logging failed for ${ticker}:`, err);
    return NextResponse.json(
      { error: err.message || 'Failed to calculate prediction' },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { PredictionsDbService } from '@/lib/predictions-db';

export const dynamic = 'force-dynamic';

export async function GET(request: NextRequest) {
  try {
    const origin = request.nextUrl.origin;
    const stats = await PredictionsDbService.getVerificationStats('ALL', origin);

    // Fetch recently verified predictions for public auditing
    const allPredictions = await PredictionsDbService.getAllPredictions();
    const verifiedPredictions = allPredictions
      .filter(r => r.status === 'VERIFIED')
      .sort((a, b) => new Date(b.verification_date || '').getTime() - new Date(a.verification_date || '').getTime())
      .slice(0, 10)
      .map(r => ({
        id: r.id,
        ticker: r.ticker,
        prediction_date: r.prediction_date,
        timeframe: r.timeframe,
        current_price: r.current_price,
        predicted_price: r.predicted_price,
        predicted_direction: r.predicted_direction,
        confidence_score: r.confidence_score,
        actual_price: r.actual_price,
        actual_direction: r.actual_direction,
        prediction_result: r.prediction_result,
        error_percentage: r.error_percentage,
        verification_date: r.verification_date,
      }));

    // Calculate average confidence score
    const allVerified = allPredictions.filter(r => r.status === 'VERIFIED');
    const avgConfidence = allVerified.length > 0
      ? allVerified.reduce((s, r) => s + r.confidence_score, 0) / allVerified.length
      : 0;

    return NextResponse.json({
      accuracy: stats.tradeableAccuracy ?? stats.accuracy,
      overallAccuracy: stats.overallModelAccuracy ?? stats.accuracy,
      tradeableAccuracy: stats.tradeableAccuracy ?? stats.accuracy,
      totalCount: stats.totalCount,
      totalVerified: stats.totalCount,
      filteredPredictionsCount: stats.filteredPredictionsCount,
      noSignalCount: stats.noSignalCount,
      avgConfidence: Number(avgConfidence.toFixed(1)),
      confidenceCalibration: stats.confidenceCalibration,
      accuracyTrend: stats.accuracyTrend,
      recentVerified: verifiedPredictions,
      accuracyByModel: stats.accuracyByModel,
      avgError: stats.avgError,
      medianError: stats.medianError,
      winLossRatioAfterFiltering: stats.winLossRatioAfterFiltering,
      brierScore: stats.brierScore,
      overallWinLossRatio: stats.overallWinLossRatio ?? stats.winLossRatio,
      accuracyBeforeFiltering: stats.accuracyBeforeFiltering ?? stats.accuracy,
      accuracyAfterFiltering: stats.accuracyAfterFiltering ?? stats.tradeableAccuracy ?? stats.accuracy,
      failureAnalysis: stats.failureAnalysis,
      stockReliability: stats.stockReliability ?? stats.accuracyByStock,
      timeframeReliability: stats.timeframeReliability,
      confidenceBucketPerformance: stats.confidenceBucketPerformance,
      targetAchieved: stats.targetAchieved,
    });
  } catch (err: any) {
    console.error('Failed to fetch public trust stats:', err);
    return NextResponse.json({ error: err.message || 'Failed to retrieve trust statistics.' }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { supabase } from '@/lib/supabase';
import { calculateIndicators } from '@/lib/indicators';
import { StockData, HistoricalQuote, StockQuote } from '@/types/stock';

export const dynamic = 'force-dynamic';

export function generateMockStockData(ticker: string): StockData {
  const cleanTicker = ticker.toUpperCase();
  const nameMap: Record<string, { name: string; exchange: string; price: number }> = {
    AAPL: { name: 'Apple Inc.', exchange: 'NASDAQ', price: 189.43 },
    MSFT: { name: 'Microsoft Corporation', exchange: 'NASDAQ', price: 420.55 },
    GOOGL: { name: 'Alphabet Inc.', exchange: 'NASDAQ', price: 175.30 },
    TSLA: { name: 'Tesla Inc.', exchange: 'NASDAQ', price: 177.46 },
    AMZN: { name: 'Amazon.com Inc.', exchange: 'NASDAQ', price: 185.15 },
    'RELIANCE.BSE': { name: 'Reliance Industries Ltd', exchange: 'BSE', price: 2950.00 },
    NIFTY: { name: 'NIFTY 50 Index', exchange: 'NSE', price: 22300.00 },
  };

  const info = nameMap[cleanTicker] || {
    name: `${cleanTicker} Corporation`,
    exchange: 'NYSE',
    price: 100 + Math.random() * 200,
  };

  const history: HistoricalQuote[] = [];
  let currentPrice = info.price;
  const baseDate = new Date();

  // Generate 100 days of daily data
  for (let i = 130; i >= 0; i--) {
    const d = new Date(baseDate);
    d.setDate(baseDate.getDate() - i);
    // skip weekends for realistic stock data
    const day = d.getDay();
    if (day === 0 || day === 6) continue;

    const change = currentPrice * (Math.random() - 0.485) * 0.025; // slight upward drift
    const open = currentPrice;
    const close = currentPrice + change;
    const high = Math.max(open, close) + Math.random() * (currentPrice * 0.008);
    const low = Math.min(open, close) - Math.random() * (currentPrice * 0.008);
    const volume = Math.floor(500000 + Math.random() * 20000000);

    history.push({
      date: d.toISOString().split('T')[0],
      open: Number(open.toFixed(2)),
      high: Number(high.toFixed(2)),
      low: Number(low.toFixed(2)),
      close: Number(close.toFixed(2)),
      volume,
    });

    currentPrice = close;
  }

  // Cap compact history to last 100 trading days
  const compactHistory = history.slice(-100);

  const lastQuote = compactHistory[compactHistory.length - 1];
  const previousClose = compactHistory[compactHistory.length - 2]?.close || lastQuote.close * 0.98;
  const changePercent = ((lastQuote.close - previousClose) / previousClose) * 100;

  const quote: StockQuote = {
    price: lastQuote.close,
    open: lastQuote.open,
    high: lastQuote.high,
    low: lastQuote.low,
    volume: lastQuote.volume,
    changePercent: Number(changePercent.toFixed(2)),
    previousClose: Number(previousClose.toFixed(2)),
  };

  const indicators = calculateIndicators(compactHistory);

  return {
    ticker: cleanTicker,
    name: info.name,
    exchange: info.exchange,
    currency: 'USD',
    quote,
    history: compactHistory,
    indicators,
  };
}

export async function getStockDataInternal(ticker: string): Promise<StockData> {
  const cleanTicker = ticker.toUpperCase();
  const apiKey = process.env.ALPHA_VANTAGE_API_KEY;
  const cacheTtlMs = 15 * 60 * 1000; // 15 minutes cache TTL

  try {
    // 1. Try to fetch from Supabase stock_cache
    if (process.env.NEXT_PUBLIC_SUPABASE_URL) {
      const { data: cached, error } = await supabase
        .from('stock_cache')
        .select('*')
        .eq('ticker', cleanTicker)
        .single();

      if (cached && !error) {
        const cacheAge = Date.now() - new Date(cached.cached_at).getTime();
        if (cacheAge < cacheTtlMs) {
          return cached.data as StockData;
        }
      }
    }
  } catch (err) {
    console.error('Supabase read error, bypassing cache:', err);
  }

  // 2. Fetch from Alpha Vantage if API Key exists
  if (apiKey && apiKey !== 'your_alpha_vantage_key') {
    try {
      const url = `https://www.alphavantage.co/query?function=TIME_SERIES_DAILY_ADJUSTED&symbol=${cleanTicker}&apikey=${apiKey}&outputsize=compact`;
      const res = await fetch(url, { cache: 'no-store' });
      const data = await res.json();

      const timeSeries = data?.['Time Series (Daily)'];
      const metaData = data?.['Meta Data'];

      if (timeSeries && metaData) {
        // Format daily prices
        const history: HistoricalQuote[] = Object.entries(timeSeries)
          .map(([dateStr, val]: [string, any]) => ({
            date: dateStr,
            open: parseFloat(val['1. open']),
            high: parseFloat(val['2. high']),
            low: parseFloat(val['3. low']),
            close: parseFloat(val['4. close']),
            volume: parseInt(val['6. volume']),
          }))
          .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());

        if (history.length > 0) {
          const lastQuote = history[history.length - 1];
          const previousClose = history[history.length - 2]?.close || lastQuote.close;
          const changePercent = ((lastQuote.close - previousClose) / previousClose) * 100;

          const quote: StockQuote = {
            price: lastQuote.close,
            open: lastQuote.open,
            high: lastQuote.high,
            low: lastQuote.low,
            volume: lastQuote.volume,
            changePercent: Number(changePercent.toFixed(2)),
            previousClose: Number(previousClose.toFixed(2)),
          };

          const indicators = calculateIndicators(history);

          const stockData: StockData = {
            ticker: cleanTicker,
            name: metaData['2. Symbol'] ? `${metaData['2. Symbol']} Corp` : `${cleanTicker} Inc.`,
            exchange: 'NASDAQ', // Standard default exchange
            currency: 'USD',
            quote,
            history,
            indicators,
          };

          // 3. Save to Supabase Cache in background
          if (process.env.NEXT_PUBLIC_SUPABASE_URL) {
            try {
              await supabase
                .from('stock_cache')
                .upsert(
                  { ticker: cleanTicker, data: stockData, cached_at: new Date().toISOString() },
                  { onConflict: 'ticker' }
                );
            } catch (err) {
              console.error('Failed to cache stock data in Supabase:', err);
            }
          }

          return stockData;
        }
      } else {
        console.warn(`Alpha Vantage API rate limit or error for ${cleanTicker}. Using mock fallback.`);
      }
    } catch (err) {
      console.error(`Error querying Alpha Vantage API for ticker ${cleanTicker}:`, err);
    }
  }

  // 4. Try to return expired cache if active API query failed
  if (process.env.NEXT_PUBLIC_SUPABASE_URL) {
    try {
      const { data: expiredCache } = await supabase
        .from('stock_cache')
        .select('data')
        .eq('ticker', cleanTicker)
        .single();

      if (expiredCache?.data) {
        return expiredCache.data as StockData;
      }
    } catch (err) {
      console.error('Failed to retrieve expired cache:', err);
    }
  }

  // 5. Fallback to mock data
  const mockData = generateMockStockData(cleanTicker);

  // Save mock data to cache so subsequent requests don't hit limits
  if (process.env.NEXT_PUBLIC_SUPABASE_URL) {
    try {
      await supabase
        .from('stock_cache')
        .upsert(
          { ticker: cleanTicker, data: mockData, cached_at: new Date().toISOString() },
          { onConflict: 'ticker' }
        );
    } catch (err) {
      console.error('Failed to cache mock data:', err);
    }
  }

  return mockData;
}

export async function GET(
  request: NextRequest,
  { params }: { params: Promise<{ ticker: string }> }
