  async updateVerifiedPrediction(
    id: string,
    updates: {
      actual_price: number;
      actual_direction: 'UP' | 'DOWN' | 'NEUTRAL';
      prediction_result: 'CORRECT' | 'INCORRECT' | 'PARTIALLY_CORRECT' | 'NEUTRAL';
